export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:10。區民館休息區。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "閱覽室的燈被隔壁時段的人借走了。佐伯把文件套收進舊電腦包，拉鏈拉了兩次。兩個人移到走廊盡頭的休息區。自動販賣機嗡嗡響。桌上擺著便利店買的飯糰和一瓶茶。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯拆飯糰的包裝。動作很慢。像在確認拉鏈和包裝是同一種程序。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "為什麼你們都不直接去筑波？", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有提 no_moon。沒有提那個帶倒月感的帳號。沒有提任何叫她不要去的人。她只問了這一句。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯所有方向都指向茨城。筑波附近。研究聯絡地址。機構名稱。可是沒有一個家屬去過。水瀨沒去。藤川沒去。佐伯也沒去。他們不是不想去。他們是選擇不去。我要知道為什麼。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "有人去過。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他咬了一口飯糰。嚼了幾下。吞下去。然後繼續。像在念一張已經讀過很多次的清單。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "去年秋天。一個家屬拿著研究通知，直接去了筑波那邊的聯絡地址。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "沒有預約。到了門口。被保安擋下來。說這裡不對外開放，要事先聯絡。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "家屬在門口等了兩個小時。不肯走。保安報了警。警方以現場滋擾紀錄處理。沒有逮捕。沒有起訴。只是留了紀錄。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯滋擾。不是非法侵入。不是威脅。是滋擾。最輕的那種。但也是最方便的那種。它讓一個家長變成紀錄上的麻煩，而不是紀錄上的申訴人。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "隔天，那個家屬的公開尋人頁上，原本寫著研究機構名稱。被管理員移除了。理由是「未經確認的關聯，可能涉及名譽風險」。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "同一天，學校寄出更正通知。說追加檢查從未正式成立。說那只是「一般健康問卷的延伸說明」。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "原本的研究頁面改成了個資公告。聯絡方式還在。但計畫名稱、招募條件、第二階段說明——全部不見了。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "最後，家屬收到提醒。不要再前往私有設施。如果需要查詢，請透過正式窗口。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說完了。把飯糰剩下的半個放回桌上。像在收一份證據。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯沒有黑衣人。沒有威脅電話。沒有失蹤。只是一連串看起來都合理的程序。保安擋人。警方記錄。頁面管理。學校更正。個資公告。每一環都合法。每一環都普通。可是串起來之後，那個家屬手上的資料就少了。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "所以不是有人阻止你們去。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "沒有人阻止。是去了之後，東西會消失。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "也許只是機構發現個資外洩，開始補洞。也許不是。但結果一樣——妳去得太早，留下的資料就會變少。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著桌上那瓶沒有打開的茶。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是超自然禁區。不是詛咒。不是神秘力量把筑波封起來。是制度。是程序。是一套會在有人靠近時自動收縮的資料外殼。你越早碰它，它越快把可以碰到的東西收回去了。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯所以家屬圈不是永遠不去。是先存東西。先存公開文件。先做副本。先確認共同後台。先讓資料不會因為一個頁面消失就全部斷線。然後才去。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "我們不是不去。是還不能去。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "今天比的就是這個。先把紙上的東西固定下來。等它們固定了，再決定下一步。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:25。飯糰吃完了。茶還沒打開。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把包裝紙揉成一團。站起來。把電腦包背上。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "附近有一間公共圖書館。有資料終端。不連外網，但可以查法人登記和舊研討會資料。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "TKS。去查它。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪把茶擰開。喝了一口。涼的。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯TKS。頁尾那三個字母。四套不同名稱的文件，頁尾都帶著它。它看起來像普通列印碼。可是它不是。它是同一個後台的簽名。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯現在要去查它。不是去筑波。不是去碰設施。是去查一間公司的名字。用公開資料。用圖書館。用任何人都可以查的東西。", background: Background.Chapter_12_Ch12_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:30。兩個人走出區民館。下午的光比早上白。風從河邊過來。帶著一點水氣。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有問佐伯那個去筑波的家屬是誰。她不需要知道。她只需要知道結果。", background: Background.Chapter_12_Ch12_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "資料會變少。所以先存資料。先固定。再移動。", background: Background.Chapter_12_Ch12_Act7_S0 },
];
